-- VIOLATES 2NF: course_name depends only on course_id, not on (student_id, course_id)
-- CREATE TABLE enrollments_bad (
--   student_id INT,
--   course_id INT,
--   course_name VARCHAR(80),  <- partial dependency on course_id alone!
--   student_name VARCHAR(50), <- partial dependency on student_id alone!
--   grade CHAR(2),
--   PRIMARY KEY (student_id, course_id)
-- );

-- 2NF SOLUTION: separate tables
CREATE TABLE students (
  student_id INT PRIMARY KEY,
  student_name VARCHAR(50)
);

CREATE TABLE courses (
  course_id INT PRIMARY KEY,
  course_name VARCHAR(80)
);

CREATE TABLE enrollments (
  student_id INT,
  course_id INT,
  grade CHAR(2),
  PRIMARY KEY (student_id, course_id),
  FOREIGN KEY (student_id) REFERENCES students(student_id),
  FOREIGN KEY (course_id) REFERENCES courses(course_id)
);

INSERT INTO students VALUES (1,'Alice'),(2,'Bob'),(3,'Carol');
INSERT INTO courses  VALUES (101,'Database Fundamentals'),(102,'Web Development');
INSERT INTO enrollments VALUES (1,101,'A'),(1,102,'B+'),(2,101,'B'),(3,102,'A-');

-- Query: Show all enrollments with names
SELECT s.student_name, c.course_name, e.grade
FROM enrollments e
JOIN students s ON e.student_id = s.student_id
JOIN courses  c ON e.course_id  = c.course_id
ORDER BY s.student_name;
